insert into public.gold_providers (id, name, acronym, category, description, url, color, price_mode, is_deleted) values
  ('1', 'SJC (Vàng bạc Đá quý Sài Gòn)', 'SJC', 'enterprise', 'Thương hiệu vàng quốc gia hàng đầu tại Việt Nam, chuyên cung cấp vàng miếng SJC tiêu chuẩn và trang sức cao cấp.', 'https://sjc.com.vn', 'linear-gradient(135deg, #FFE07D 0%, #D4AF37 100%)', 'auto', false),
  ('2', 'DOJI (Tập đoàn Vàng bạc Đá quý DOJI)', 'DOJI', 'enterprise', 'Tập đoàn kinh doanh vàng bạc đá quý hàng đầu Việt Nam, nổi tiếng với công nghệ gia công kim cương, đá quý và vàng miếng.', 'https://doji.vn', 'linear-gradient(135deg, #EF4444 0%, #B91C1C 100%)', 'auto', false),
  ('3', 'PNJ (Vàng bạc Đá quý Phú Nhuận)', 'PNJ', 'enterprise', 'Thương hiệu bán lẻ trang sức hàng đầu châu Á, nổi bật với hệ thống cửa hàng trải dài toàn quốc và chế tác tinh xảo.', 'https://www.pnj.com.vn', 'linear-gradient(135deg, #1E3A8A 0%, #0D9488 100%)', 'auto', false),
  ('4', 'Bảo Tín Minh Châu', 'BTMC', 'enterprise', 'Một trong những thương hiệu vàng uy tín lâu đời nhất miền Bắc, nổi tiếng với dòng sản phẩm vàng Rồng Thăng Long 999.9.', 'https://btmc.vn', 'linear-gradient(135deg, #854D0E 0%, #A16207 100%)', 'auto', false),
  ('5', 'Phú Quý (Tập đoàn Phú Quý)', 'PQ', 'enterprise', 'Chuyên kinh doanh phân phối vàng miếng, vàng mỹ nghệ và trang sức cưới chất lượng cao được ưa chuộng tại Việt Nam.', 'https://phuquy.com.vn', 'linear-gradient(135deg, #EA580C 0%, #9A3412 100%)', 'auto', false),
  ('6', 'Bảo Tín Mạnh Hải', 'BTMH', 'enterprise', 'Thương hiệu vàng trang sức và tích lũy uy tín, kế thừa tinh hoa chế tác kim hoàn lâu năm của dòng họ Bảo Tín.', 'https://baotinmanhhai.vn', 'linear-gradient(135deg, #9D174D 0%, #BE185D 100%)', 'auto', false),
  ('7', 'VietinBank Gold', 'VTBG', 'enterprise', 'Trực thuộc VietinBank, chuyên doanh vàng miếng SJC, quà tặng mạ vàng cao cấp, kim cương và đá quý đạt chuẩn quốc tế.', 'https://vietinbankgold.vn', 'linear-gradient(135deg, #0284C7 0%, #0F172A 100%)', 'auto', false),
  ('8', 'Sacombank-SBJ', 'SBJ', 'enterprise', 'Chuyên sản xuất các dòng sản phẩm quà tặng vàng mỹ nghệ cao cấp, vàng miếng tích trữ và trang sức cưới tinh tế.', 'https://sacombank-sbj.com', 'linear-gradient(135deg, #0891B2 0%, #0369A1 100%)', 'auto', false),
  ('9', 'HanaGold (Vàng công nghệ)', 'HNG', 'enterprise', 'Tiên phong trong mô hình ứng dụng công nghệ số vào tích lũy vàng, cho phép khách hàng mua tích trữ vàng trực tuyến.', 'https://hanagold.vn', 'linear-gradient(135deg, #6366F1 0%, #4F46E5 100%)', 'auto', false),
  ('10', 'Mi Hồng (Vàng Mi Hồng)', 'MH', 'enterprise', 'Thương hiệu vàng bạc đá quý vô cùng uy tín và quen thuộc tại khu vực TP. Hồ Chí Minh và các tỉnh phía Nam.', 'https://mihong.vn', 'linear-gradient(135deg, #F59E0B 0%, #D97706 100%)', 'auto', false),
  ('11', 'Ngọc Thẫm Jewelry (NTJ)', 'NTJ', 'enterprise', 'Một trong những thương hiệu kim hoàn lớn nhất miền Tây Nam Bộ, chuyên sản xuất các dòng sản phẩm trang sức vàng tinh xảo.', 'https://ngoctham.com.vn', 'linear-gradient(135deg, #0D9488 0%, #115E59 100%)', 'auto', false),
  ('12', 'Kim Tín (Tập đoàn Kim Tín)', 'KT', 'enterprise', 'Đơn vị chế tác, sản xuất và phân phối vàng bạc đá quý lớn tại khu vực phía Bắc với công nghệ máy đo tuổi vàng hiện đại.', 'http://kimtin.com.vn', 'linear-gradient(135deg, #A855F7 0%, #7E22CE 100%)', 'auto', false),
  ('13', 'Huy Thanh Jewelry', 'HTJ', 'enterprise', 'Nổi tiếng với các thiết kế nhẫn cưới trẻ trung, hiện đại, phong cách Hàn Quốc hướng tới đối tượng khách hàng trẻ.', 'https://huythanhjewelry.vn', 'linear-gradient(135deg, #EC4899 0%, #BE185D 100%)', 'auto', false),
  ('14', 'Sinh Diễn (Vàng bạc Sinh Diễn)', 'SD', 'enterprise', 'Thương hiệu vàng bạc đá quý lớn nhất khu vực Bắc Ninh và Bắc Giang với độ uy tín cao, giá niêm yết cạnh tranh.', 'https://sinhdien.com.vn', 'linear-gradient(135deg, #10B981 0%, #059669 100%)', 'auto', false),
  ('15', 'Bảo Tín Kim Chung (Thái Bình)', 'BTKC', 'enterprise', 'Đơn vị cung cấp vàng miếng SJC và trang sức hàng đầu Thái Bình, kiểm định tuổi vàng chặt chẽ bằng máy quang phổ.', 'https://baotinkimchung.com', 'linear-gradient(135deg, #F59E0B 0%, #D97706 100%)', 'auto', false),
  ('16', 'Ngọc Hải Jewelry (Mỹ Tho)', 'NHJ', 'enterprise', 'Thương hiệu vàng bạc trang sức uy tín hàng đầu Tiền Giang và miền Tây Nam Bộ với hơn 30 năm hoạt động.', 'https://ngochai.vn', 'linear-gradient(135deg, #3B82F6 0%, #2563EB 100%)', 'auto', false),
  ('17', 'Vàng bạc Phước Hùng (Chợ Thiếc)', 'PHG', 'enterprise', 'Chuyên trao đổi sỉ lẻ các loại vàng miếng 24K, nhẫn tròn trơn và trang sức trung cấp tại trung tâm vàng Chợ Thiếc, TP.HCM.', 'http://phuochunggold.com', 'linear-gradient(135deg, #6B7280 0%, #4B5563 100%)', 'auto', false),
  ('18', 'Vàng bạc Kim Vinh (Đà Nẵng)', 'KVG', 'enterprise', 'Nhà cung cấp vàng miếng SJC và vàng nhẫn 99.99 uy tín lâu năm tại thị trường miền Trung và TP. Đà Nẵng.', 'https://kimvinh.vn', 'linear-gradient(135deg, #EF4444 0%, #DC2626 100%)', 'auto', false),
  ('19', 'Eximbank', 'EIB', 'bank', 'Một trong những ngân hàng thương mại cập nhật biểu giá giao dịch vàng miếng SJC nhanh chóng và đầy đủ nhất thị trường.', 'https://eximbank.com.vn', 'linear-gradient(135deg, #2563EB 0%, #1D4ED8 100%)', 'auto', false),
  ('20', 'Agribank', 'AGR', 'bank', 'Ngân hàng quốc doanh lớn nhất Việt Nam được cấp phép trực tiếp bán vàng miếng SJC bình ổn giá đến tay người dân.', 'https://www.agribank.com.vn', 'linear-gradient(135deg, #15803D 0%, #166534 100%)', 'auto', false),
  ('21', 'Vietcombank', 'VCB', 'bank', 'Ngân hàng thương mại hàng đầu Việt Nam cung cấp dịch vụ đăng ký mua vàng miếng SJC trực tuyến vô cùng thuận tiện.', 'https://portal.vietcombank.com.vn', 'linear-gradient(135deg, #059669 0%, #047857 100%)', 'auto', false),
  ('22', 'BIDV', 'BIDV', 'bank', 'Thành viên nhóm Big 4 ngân hàng Việt Nam hỗ trợ bán vàng miếng SJC bình ổn giá theo định hướng của Ngân hàng Nhà nước.', 'https://bidv.com.vn', 'linear-gradient(135deg, #1D4ED8 0%, #1E3A8A 100%)', 'auto', false),
  ('23', 'ACB (Ngân hàng Á Châu)', 'ACB', 'bank', 'Thực hiện mua bán, giao dịch vàng miếng SJC tại các chi nhánh trọng điểm với thủ tục nhanh gọn, an toàn và bảo mật.', 'https://acb.com.vn', 'linear-gradient(135deg, #0284C7 0%, #0369A1 100%)', 'auto', false),
  ('24', 'TPBank', 'TPB', 'bank', 'Liên kết chặt chẽ với Tập đoàn DOJI trong các dịch vụ tài chính về vàng và giao dịch mua bán vàng miếng chất lượng.', 'https://tpb.vn', 'linear-gradient(135deg, #7C3AED 0%, #5B21B6 100%)', 'auto', false),
  ('25', 'Sacombank', 'STB', 'bank', 'Điểm giao dịch mua bán vàng miếng uy tín với chính sách tỷ giá linh hoạt và các gói dịch vụ giữ hộ vàng an toàn.', 'https://www.sacombank.com.vn', 'linear-gradient(135deg, #0369A1 0%, #1E3A8A 100%)', 'auto', false),
  ('26', 'Techcombank', 'TCB', 'bank', 'Ngân hàng thương mại cổ phần lớn hàng đầu Việt Nam được Ngân hàng Nhà Nước cấp phép kinh doanh vàng miếng SJC.', 'https://techcombank.com', 'linear-gradient(135deg, #EA580C 0%, #B91C1C 100%)', 'auto', false),
  ('27', 'HDBank', 'HDB', 'bank', 'Mạng lưới chi nhánh giao dịch vàng miếng SJC rộng khắp cả nước với bảng giá ngoại tệ và vàng miếng chuẩn xác.', 'https://hdbank.com.vn', 'linear-gradient(135deg, #F97316 0%, #EA580C 100%)', 'auto', false),
  ('28', 'MSB (Ngân hàng Hàng Hải)', 'MSB', 'bank', 'Thực hiện các nghiệp vụ giao dịch, mua bán vàng miếng SJC trực tiếp tại quầy giao dịch chi nhánh lớn.', 'https://msb.com.vn', 'linear-gradient(135deg, #F43F5E 0%, #E11D48 100%)', 'auto', false),
  ('29', 'SCB (Ngân hàng Sài Gòn)', 'SCB', 'bank', 'Đại lý phân phối và giao dịch vàng miếng SJC tiêu chuẩn tại các chi nhánh được ngân hàng nhà nước cấp giấy phép.', 'https://scb.com.vn', 'linear-gradient(135deg, #06B6D4 0%, #0891B2 100%)', 'auto', false),
  ('30', 'VPBank', 'VPB', 'bank', 'Hỗ trợ khách hàng giao dịch vàng miếng SJC tích lũy qua hệ thống ngân hàng số VPBank NEO và chi nhánh.', 'https://vpbank.com.vn', 'linear-gradient(135deg, #10B981 0%, #059669 100%)', 'auto', false),
  ('31', 'MB Bank (Ngân hàng Quân Đội)', 'MBB', 'bank', 'Điểm giao dịch vàng miếng SJC bảo mật và an toàn dưới sự giám sát chặt chẽ của Bộ Quốc Phòng Việt Nam.', 'https://mbbank.com.vn', 'linear-gradient(135deg, #1D4ED8 0%, #1E3A8A 100%)', 'auto', false),
  ('32', 'SHB (Ngân hàng Sài Gòn - Hà Nội)', 'SHB', 'bank', 'Thực hiện mua bán vàng miếng SJC chính hãng, cập nhật giá niêm yết theo quy định kiểm soát của Nhà Nước.', 'https://shb.com.vn', 'linear-gradient(135deg, #F59E0B 0%, #D97706 100%)', 'auto', false),
  ('33', 'LPBank', 'LPB', 'bank', 'Hỗ trợ giao dịch vàng miếng SJC an toàn, minh bạch thông qua hệ thống bưu điện và phòng giao dịch khắp 63 tỉnh thành.', 'https://lpbank.com.vn', 'linear-gradient(135deg, #F59E0B 0%, #B45309 100%)', 'auto', false),
  ('34', 'SeABank', 'SEAB', 'bank', 'Cung cấp dịch vụ mua bán vàng miếng SJC chuẩn quốc gia với quy trình bảo mật cao và thủ tục nhanh gọn.', 'https://seabank.com.vn', 'linear-gradient(135deg, #EF4444 0%, #991B1B 100%)', 'auto', false),
  ('35', 'Webgiá (WG)', 'WG', 'aggregator', 'Chuyên trang cập nhật bảng tỷ giá tài sản, biểu đồ giá vàng, tỷ giá ngoại tệ, xăng dầu và lãi suất tại Việt Nam.', 'https://webgia.com', 'linear-gradient(135deg, #059669 0%, #047857 100%)', 'auto', false),
  ('36', 'Chợ Giá (CG)', 'CG', 'aggregator', 'Cổng thông tin tổng hợp cập nhật giá vàng thế giới và giá vàng SJC, vàng nhẫn trong nước theo phút.', 'https://chogia.vn', 'linear-gradient(135deg, #0284C7 0%, #0369A1 100%)', 'auto', false),
  ('37', 'Giá Vàng Org (GVO)', 'GVO', 'aggregator', 'Chuyên cung cấp tin tức nhận định thị trường vàng bạc đá quý, tỷ giá ngân hàng và bảng so sánh giá vàng các tỉnh.', 'https://giavang.org', 'linear-gradient(135deg, #D4AF37 0%, #8A6605 100%)', 'auto', false),
  ('38', 'Giá Vàng Net (GVN)', 'GVN', 'aggregator', 'Trang tin tức chuyên phân tích thị trường vàng thế giới và diễn biến giá vàng SJC trong nước trực quan.', 'https://giavang.net', 'linear-gradient(135deg, #EA580C 0%, #C2410C 100%)', 'auto', false),
  ('39', 'CafeF Giá Vàng (CFF)', 'CFF', 'aggregator', 'Trang tài chính kinh tế hàng đầu, cung cấp số liệu chuyên sâu về diễn biến vàng miếng và chính sách tiền tệ vĩ mô.', 'https://cafef.vn', 'linear-gradient(135deg, #1F2937 0%, #111827 100%)', 'auto', false),
  ('40', '24hMoney (24M)', '24M', 'aggregator', 'Mạng xã hội tài chính cá nhân lớn cập nhật so sánh bảng giá vàng miếng, vàng nhẫn trực tuyến nhanh nhất.', 'https://24hmoney.vn', 'linear-gradient(135deg, #4F46E5 0%, #3730A3 100%)', 'auto', false),
  ('41', 'VnExpress Vàng (VNE)', 'VNE', 'aggregator', 'Trang báo điện tử hàng đầu với chuyên mục biểu đồ giá vàng SJC trong nước và thế giới trực quan.', 'https://vnexpress.net', 'linear-gradient(135deg, #991B1B 0%, #7F1D1D 100%)', 'auto', false)
